import{_ as e,o as a,c as o,ag as r}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"DNA Import","description":"","frontmatter":{},"headers":[],"relativePath":"guide/dna-import.md","filePath":"guide/dna-import.md","lastUpdated":1774598042000}'),i={name:"guide/dna-import.md"};function n(s,t,l,d,c,h){return a(),o("div",null,[...t[0]||(t[0]=[r(`<h1 id="dna-import" tabindex="-1">DNA Import <a class="header-anchor" href="#dna-import" aria-label="Permalink to &quot;DNA Import&quot;">​</a></h1><p>getbased can overlay genetic context on your blood work. Drop a raw DNA file from any major provider and getbased matches health-relevant SNPs to the biomarkers you&#39;re already tracking — so the AI can factor in your genetics when interpreting lab results.</p><h2 id="before-you-start" tabindex="-1">Before You Start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before You Start&quot;">​</a></h2><p>You need a <strong>raw DNA data file</strong> from one of these providers:</p><table tabindex="0"><thead><tr><th>Provider</th><th>File format</th><th>How to download</th></tr></thead><tbody><tr><td><strong>AncestryDNA</strong></td><td>Tab-separated text</td><td>Settings → DNA → Download Raw DNA Data</td></tr><tr><td><strong>23andMe</strong></td><td>Tab-separated text</td><td>Settings → 23andMe Data → Download Raw Data</td></tr><tr><td><strong>MyHeritage</strong></td><td>CSV</td><td>DNA → Manage DNA kits → Download Raw Data</td></tr><tr><td><strong>FTDNA</strong> (Family Tree DNA)</td><td>CSV</td><td>myFTDNA → Download Raw Data</td></tr><tr><td><strong>Living DNA</strong></td><td>Tab-separated text</td><td>Dashboard → Download Raw DNA</td></tr></tbody></table><p>No AI provider is needed for DNA import — the file is parsed locally.</p><h2 id="how-to-import" tabindex="-1">How to Import <a class="header-anchor" href="#how-to-import" aria-label="Permalink to &quot;How to Import&quot;">​</a></h2><ol><li>Open the getbased dashboard</li><li>Drop your DNA file onto the page (or use the import button and select the file)</li><li>Review the <strong>import preview</strong> — SNPs are grouped by impact level</li><li>Click <strong>Import</strong> to save</li></ol><p>The file is processed entirely in your browser using a Web Worker. Your DNA data is never transmitted anywhere.</p><h2 id="what-gets-extracted" tabindex="-1">What Gets Extracted <a class="header-anchor" href="#what-gets-extracted" aria-label="Permalink to &quot;What Gets Extracted&quot;">​</a></h2><p>getbased doesn&#39;t store your entire genome. It scans your file for <strong>42 curated SNPs</strong> across 10 categories and discards everything else.</p><table tabindex="0"><thead><tr><th>Category</th><th>SNPs</th><th>Example genes</th><th>Related markers</th></tr></thead><tbody><tr><td>Methylation</td><td>6</td><td>MTHFR, MTR, MTRR, CBS</td><td>Homocysteine, folate, B12</td></tr><tr><td>Iron</td><td>5</td><td>HFE, TMPRSS6, TF</td><td>Ferritin, transferrin, iron</td></tr><tr><td>Lipids</td><td>5</td><td>APOE, PCSK9, CETP</td><td>LDL, HDL, cholesterol, Lp(a)</td></tr><tr><td>Vitamin D</td><td>4</td><td>VDR, GC, CYP2R1</td><td>Vitamin D</td></tr><tr><td>Vitamin B12</td><td>4</td><td>FUT2, TCN2, CUBN</td><td>B12, homocysteine</td></tr><tr><td>Blood Sugar</td><td>4</td><td>TCF7L2, PPARG, ADIPOQ</td><td>Glucose, HbA1c, insulin</td></tr><tr><td>Sex Hormones</td><td>5</td><td>SHBG, CYP17A1, CYP19A1</td><td>Testosterone, estradiol, SHBG</td></tr><tr><td>Thyroid</td><td>3</td><td>DIO1, DIO2, TSHR</td><td>TSH, fT3, fT4</td></tr><tr><td>Bilirubin</td><td>2</td><td>UGT1A1</td><td>Total bilirubin</td></tr><tr><td>Fatty Acids</td><td>4</td><td>FADS1, FADS2, ELOVL2</td><td>Omega-3, EPA, DHA</td></tr></tbody></table><h3 id="apoe-haplotype" tabindex="-1">APOE Haplotype <a class="header-anchor" href="#apoe-haplotype" aria-label="Permalink to &quot;APOE Haplotype&quot;">​</a></h3><p>The two APOE SNPs (rs429358 + rs7412) are automatically resolved into the standard haplotype notation (ε2/ε3/ε4) rather than shown as raw genotypes.</p><h2 id="how-snps-are-selected" tabindex="-1">How SNPs Are Selected <a class="header-anchor" href="#how-snps-are-selected" aria-label="Permalink to &quot;How SNPs Are Selected&quot;">​</a></h2><p>The curated list follows strict criteria — this is not a 23andMe-style trait report:</p><ol><li><strong>Must map to a tracked biomarker.</strong> Every SNP links to at least one marker in the getbased schema. Pure ancestry or trait SNPs are excluded</li><li><strong>Known mechanism.</strong> The variant directly affects an enzyme, receptor, or transport protein in a biochemically understood way — not just a statistical GWAS association with a tiny odds ratio</li><li><strong>Large effect size.</strong> Included SNPs have meaningful clinical impact (e.g., MTHFR C677T reduces enzyme activity to ~30%; HFE C282Y causes 10–20× iron overload risk in homozygotes)</li><li><strong>Well-replicated.</strong> Findings confirmed across multiple databases (SNPedia, ClinVar, GWAS Catalog, PharmGKB)</li><li><strong>Actionable.</strong> The genotype leads to a concrete recommendation — supplement methylfolate, monitor ferritin more closely, consider higher vitamin D targets, etc.</li></ol><p>The core principle: <strong>only SNPs that help you interpret the blood work you&#39;re already tracking</strong>.</p><h2 id="effect-tiers" tabindex="-1">Effect Tiers <a class="header-anchor" href="#effect-tiers" aria-label="Permalink to &quot;Effect Tiers&quot;">​</a></h2><p>Each genotype is classified into one of three tiers:</p><table tabindex="0"><thead><tr><th>Tier</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td>🔴 <strong>Significant</strong></td><td>Meaningful functional impact — worth factoring into your health decisions</td><td>MTHFR C677T AA (~30% enzyme activity)</td></tr><tr><td>🟡 <strong>Moderate</strong></td><td>Mild effect — relevant when combined with other factors</td><td>MTRR A66G AG (modestly reduced B12 recycling)</td></tr><tr><td>🟢 <strong>None</strong></td><td>Normal / wild-type — no impact</td><td>HFE C282Y GG (no hemochromatosis risk)</td></tr></tbody></table><p>The import preview groups findings by tier so you can see significant results first.</p><h2 id="where-genetics-appears" tabindex="-1">Where Genetics Appears <a class="header-anchor" href="#where-genetics-appears" aria-label="Permalink to &quot;Where Genetics Appears&quot;">​</a></h2><h3 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h3><p>A <strong>Genetics</strong> section shows your APOE haplotype and top findings grouped by category (methylation, iron, vitamin D, etc.), sorted by severity. The section is collapsible — click the header to expand or collapse. Initially shows up to 8 findings with a &quot;show all&quot; button for the rest. Appears after Key Trends charts. Each finding links to its primary study (PubMed) and a &quot;more studies&quot; page (SNPedia).</p><h3 id="detail-modal" tabindex="-1">Detail Modal <a class="header-anchor" href="#detail-modal" aria-label="Permalink to &quot;Detail Modal&quot;">​</a></h3><p>When you open a biomarker&#39;s detail view, any relevant SNPs appear inline — showing the gene, your genotype, and what it means for that specific marker. SNPs are sorted by severity (significant first). Each includes links to the primary study and SNPedia.</p><h3 id="ai-chat" tabindex="-1">AI Chat <a class="header-anchor" href="#ai-chat" aria-label="Permalink to &quot;AI Chat&quot;">​</a></h3><p>The AI automatically receives your genetic context when interpreting lab results. SNPs with &quot;none&quot; effect are filtered out to reduce noise. Only SNPs relevant to the markers being discussed are included, unless you explicitly ask about genetics — then the full profile is sent.</p><h3 id="context-cards" tabindex="-1">Context Cards <a class="header-anchor" href="#context-cards" aria-label="Permalink to &quot;Context Cards&quot;">​</a></h3><p>SNPs route to relevant context cards (diet, supplements, sleep, etc.) so the AI can factor them into lifestyle recommendations.</p><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><ul><li>Your DNA file is parsed <strong>entirely in your browser</strong> using a Web Worker — it is never uploaded or transmitted</li><li>Only the 42 matched SNP genotypes are stored (not your full genome)</li><li>Stored data includes: rsid, genotype, gene name, variant name, and effect classification</li><li>DNA data is included in JSON exports and covered by encryption if enabled</li><li>You can delete your genetic data at any time from the Genetics dashboard section</li><li>A <strong>Genetics</strong> entry appears in the sidebar when data is present, for quick navigation</li></ul><h2 id="re-importing" tabindex="-1">Re-importing <a class="header-anchor" href="#re-importing" aria-label="Permalink to &quot;Re-importing&quot;">​</a></h2><p>Importing a new DNA file replaces any existing genetic data for the current profile. You can re-import using the <strong>Re-import</strong> link at the bottom of the Genetics dashboard section, or by dropping a new file onto the page. This is useful if you switch DNA providers or want to update after downloading a newer raw data file.</p><h2 id="common-questions" tabindex="-1">Common Questions <a class="header-anchor" href="#common-questions" aria-label="Permalink to &quot;Common Questions&quot;">​</a></h2><p><strong>What if my file isn&#39;t detected?</strong> getbased identifies files by their content headers, not just the filename. Make sure you&#39;re using the raw data export (a text or CSV file), not a PDF report or a health report download.</p><p><strong>Why only 42 SNPs?</strong> Quality over quantity. Each SNP was selected because it has a well-understood mechanism, a large effect size, and directly helps interpret a biomarker you&#39;re tracking. Adding hundreds of low-confidence GWAS hits would create noise, not signal. Each SNP links to its primary research paper so you can verify the evidence yourself.</p><p><strong>Can I add my own SNPs?</strong> Not directly. The SNP lookup table (<code>data/snp-health.json</code>) is curated and versioned — every entry must pass the <a href="#how-snps-are-selected">five criteria above</a>. Community contributions are welcome via pull request, but <strong>you must do the research first</strong>. Open an issue with:</p><ol><li><strong>The rsID and gene/variant name</strong></li><li><strong>Which biomarker(s) it maps to</strong> in the getbased schema (e.g., <code>vitamins.folate</code>, <code>coagulation.homocysteine</code>)</li><li><strong>Mechanism</strong> — what enzyme/receptor/transporter does the variant affect, and how? (not just &quot;associated with X in a GWAS&quot;)</li><li><strong>Effect size</strong> — what is the functional impact? (e.g., &quot;reduces enzyme activity to 30%&quot; not &quot;slightly associated with&quot;)</li><li><strong>Replication</strong> — links to at least 2 independent studies or a meta-analysis confirming the effect on the specific biomarker</li><li><strong>Actionability</strong> — what concrete recommendation follows from the genotype?</li></ol><p>SNPs that fail any criterion will be declined. Common reasons for rejection:</p><ul><li>Synonymous variants with unconfirmed functional effects</li><li>GWAS associations without a known biochemical mechanism</li><li>Effects that only manifest on specialty panels (DUTCH, urinary metabolites) not standard blood work</li><li>Weak or contradictory biomarker associations (e.g., studies finding opposite directions of effect)</li><li>Variants whose pathway is already well-covered by existing SNPs (e.g., adding a third MTHFR variant when C677T and A1298C already capture the methylation story)</li><li>Pharmacogenomic SNPs that only matter on a specific drug (e.g., methotrexate response)</li></ul><p><strong>Is this a medical diagnosis?</strong> No. Genetic information provides context for interpreting your lab results — it does not diagnose conditions. Always discuss significant findings with your healthcare provider.</p><h2 id="mtdna-haplogroup-import" tabindex="-1">mtDNA Haplogroup Import <a class="header-anchor" href="#mtdna-haplogroup-import" aria-label="Permalink to &quot;mtDNA Haplogroup Import&quot;">​</a></h2><p>In addition to autosomal SNPs, getbased can import <strong>mitochondrial DNA (mtDNA)</strong> mutation files to determine your maternal haplogroup and its mitochondrial coupling status.</p><h3 id="supported-format" tabindex="-1">Supported format <a class="header-anchor" href="#supported-format" aria-label="Permalink to &quot;Supported format&quot;">​</a></h3><p>Some DNA labs (e.g., Living DNA) export mtDNA results as a simple CSV with one mutation per line:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>263G</span></span>
<span class="line"><span>462T</span></span>
<span class="line"><span>1438G</span></span>
<span class="line"><span>10398G</span></span>
<span class="line"><span>13708A</span></span></code></pre></div><p>Drop this file onto the app and getbased will:</p><ol><li>Match your mutations against diagnostic markers from <a href="https://phylotree.org/" target="_blank" rel="noreferrer">PhyloTree Build 17</a></li><li>Resolve your maternal haplogroup (e.g., J, H, U, K)</li><li>Classify your mitochondrial coupling status (coupled → uncoupled) using Doug Wallace&#39;s framework</li><li>Compare against your profile&#39;s latitude to detect <strong>environment-haplotype mismatch</strong></li></ol><h3 id="manual-entry" tabindex="-1">Manual entry <a class="header-anchor" href="#manual-entry" aria-label="Permalink to &quot;Manual entry&quot;">​</a></h3><p>If you already know your maternal haplogroup (from 23andMe results, FTDNA, or another service) but don&#39;t have a mutation file, you can enter it directly:</p><ul><li><strong>Edit Client form</strong> — select your haplogroup from the dropdown under &quot;mtDNA Haplogroup (maternal lineage)&quot;</li><li><strong>Chat onboarding</strong> — in the DNA step, use the &quot;Enter haplogroup&quot; dropdown next to the upload button</li></ul><p>Both paths auto-resolve the coupling classification and environment mismatch detection — no file needed.</p><h3 id="coupling-classification" tabindex="-1">Coupling classification <a class="header-anchor" href="#coupling-classification" aria-label="Permalink to &quot;Coupling classification&quot;">​</a></h3><p>Based on <a href="https://pubmed.ncbi.nlm.nih.gov/26406369/" target="_blank" rel="noreferrer">Wallace 2015 (Cell)</a>, mtDNA haplogroups correlate with mitochondrial electron transport coupling efficiency:</p><ul><li><strong>Coupled</strong> (L lineages) — efficient ATP production, low heat generation. Evolved in equatorial climates.</li><li><strong>Uncoupled</strong> (J, T) — more heat per calorie, less ATP. Evolved in cold northern climates.</li><li><strong>Intermediate</strong> — most other haplogroups fall between these extremes.</li></ul><p>The AI uses this to contextualize your lab results, light exposure, cold tolerance, and environmental data.</p><div class="warning custom-block"><p class="custom-block-title">Research framework</p><p>The coupling classification follows Wallace&#39;s mitochondrial paradigm — supported by cybrid studies and population data, but not universally accepted as clinical standard. Individual variation within haplogroups is significant.</p></div>`,59)])])}const m=e(i,[["render",n]]);export{u as __pageData,m as default};
